import React from 'react';
import './App.css';
import Api from './axios/api';

interface Usuario {
  id: number;
  nome: string;
}

function App() {
const [usuario, setUsuario] = React.useState<Usuario[]>([{} as Usuario]);
const BuscarTodosUsuarios= async () => {
  await Api.get("/",{
    params:{
    planilha:"usuario"
  },
  headers: {
    "Content-Type": "application/json",
    "Access-Control-Allow-Origin": "http://localhost:3000",
    "Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, OPTIONS",
    "Access-Control-Allow-Headers": "Content-Type, Authorization",
    "mode": "no-cors",
}
  }
).then((response)=>{
    setUsuario(response.data)
    console.log(response.data);
  }
  )  
  .catch((e)=> console.log(e));
}

  return (
    <div style={container}>
      <h1>Hello Mumi Braids!</h1>
      <h4> Site de Agendamento</h4>
      <div>
        <li>
          <div>
            {usuario.map((usuario)=>{
              return (
                <div>
                  <h1 key={usuario.id||undefined}> {usuario.nome}</h1>
                  </div>
              )
            })}
          </div>
        </li>
      </div>

      <button onClick={()=>BuscarTodosUsuarios()}>  Visuaisar</button>
    </div>
  );
}

export default App;

const container={
  display:"flex",
  color:"black",
  backgroundColor:"red",
  alignItems:"center",
  justifyContent:"center",
 }
